INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), 'jr', 19, 1, NULL, 'Thomas Watson em Jr 19:1', 'Segundo Thomas Watson, a piedade prática e a santificação do coração ilumina o sentido deste texto. Jeremias 19 mostra que juízo, esperança e promessa messiânica sustenta a caminhada da fé, especialmente em obediência da fé. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Thomas Watson', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'jr', 20, 1, NULL, 'Andrew Murray em Jr 20:1', 'Na leitura de Andrew Murray, vemos a coerência doutrinária aplicada à vida cristã. Jeremias 20 evidencia juízo, esperança e promessa messiânica como eixo da vida do povo de Deus, com ênfase em adoração reverente. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Andrew Murray', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'jr', 21, 1, NULL, 'Orígenes em Jr 21:1', 'Orígenes interpreta este versículo a partir de a leitura cristológica e eclesial da passagem. Em Jeremias 21, Deus revela juízo, esperança e promessa messiânica de forma pastoral e transformadora, promovendo perseverança na tribulação. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Orígenes', 'commentary', '#8B4513', NOW()),
(gen_random_uuid(), 'jr', 22, 1, NULL, 'Richard Baxter em Jr 22:1', 'Richard Baxter destaca a piedade prática e a santificação do coração. Em Jeremias 22, o foco recai sobre juízo, esperança e promessa messiânica e chama a igreja para fidelidade na aliança. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Richard Baxter', 'commentary', '#2E8B57', NOW()),
